package org.apache.flink.streaming.api.windowing.assigners;

import org.apache.flink.annotation.PublicEvolving;
import org.apache.flink.api.common.ExecutionConfig;
import org.apache.flink.api.common.typeutils.TypeSerializer;
import org.apache.flink.streaming.api.windowing.triggers.PricingSessionTrigger;
import org.apache.flink.streaming.api.windowing.triggers.Trigger;
import org.apache.flink.streaming.api.windowing.windows.TimeWindow;

import java.time.LocalTime;
import java.time.ZoneId;
import java.time.ZonedDateTime;
import java.util.Collection;
import java.util.Collections;
import java.util.HashMap;
import java.util.Map;

/**
 * A {@link WindowAssigner} that groups trading events by market session boundaries (e.g., NYSE
 * 09:30-16:00 ET, LSE 08:00-16:30 GMT). Windows are created based on market session times
 * rather than fixed time intervals.
 *
 * <p>For example, to window trading events into NYSE sessions:
 *
 * <pre>{@code
 * DataStream<TradeEvent> trades = ...;
 * KeyedStream<String, TradeEvent> keyed = trades.keyBy(t -> t.getSymbol());
 * WindowedStream<TradeEvent, String, TimeWindow> windowed =
 *   keyed.window(PricingSessionWindow.forMarket(
 *       "NYSE",
 *       ZoneId.of("America/New_York"),
 *       LocalTime.of(9, 30),
 *       LocalTime.of(16, 0)
 *   ));
 * }</pre>
 */
@PublicEvolving
public class PricingSessionWindow extends MergingWindowAssigner<Object, TimeWindow> {
    private static final long serialVersionUID = 1L;

    private final Map<String, MarketSession> marketSessions;
    private final String defaultMarketId;

    /**
     * Creates a PricingSessionWindow for the given market sessions.
     *
     * @param marketSessions Map of market ID to market session configuration
     * @param defaultMarketId The default market ID to use if not specified
     */
