            Map<String, MarketSession> marketSessions, String defaultMarketId) {
        this.marketSessions = new HashMap<>(marketSessions);
        this.defaultMarketId = defaultMarketId;
    }

    @Override
    public Collection<TimeWindow> assignWindows(
            Object element, long timestamp, WindowAssignerContext context) {
        // Use the default market for this implementation
        MarketSession session = marketSessions.get(defaultMarketId);
        if (session == null) {
            throw new IllegalArgumentException(
                    "Market session not configured for: " + defaultMarketId);
        }

        long sessionStart = session.getSessionStartTime(timestamp);
        long sessionEnd = session.getSessionEndTime(timestamp);

        return Collections.singletonList(new TimeWindow(sessionStart, sessionEnd));
    }

