            // If the event time is before the session open, it belongs to the previous session
            if (eventTime.toLocalTime().isBefore(sessionOpen)) {
                sessionStart = sessionStart.minusDays(1);
            }

            return sessionStart.toInstant().toEpochMilli();
        }

        /**
         * Gets the end time of the trading session in milliseconds since epoch for the given
         * timestamp.
         *
         * @param timestamp Event timestamp in milliseconds since epoch
         * @return Session end time in milliseconds since epoch
         */
        public long getSessionEndTime(long timestamp) {
            ZonedDateTime eventTime =
                    ZonedDateTime.ofInstant(
                            java.time.Instant.ofEpochMilli(timestamp), timezone);
            ZonedDateTime sessionStart =
                    eventTime
                            .toLocalDate()
